{
  "mode": "method",
  "tests": [
    {
      "name": "valid_challenge_id",
      "input": {
        "challenge_id": "12345"
      },
      "output": "https://api.topcoder-dev.com/challenges/12345",
      "notes": "Valid challenge ID should return the correct API URL."
    },
    {
      "name": "valid_challenge_id_with_special_characters",
      "input": {
        "challenge_id": "12345-abc"
      },
      "output": "https://api.topcoder-dev.com/challenges/12345-abc",
      "notes": "Challenge ID with special characters should still return a valid URL."
    },
    {
      "name": "invalid_challenge_id_format",
      "input": {
        "challenge_id": "abcde"
      },
      "output": "Error: Invalid challenge ID format",
      "notes": "Non-numeric challenge ID should return an error."
    },
    {
      "name": "empty_challenge_id",
      "input": {
        "challenge_id": ""
      },
      "output": "Error: Challenge ID cannot be empty",
      "notes": "Empty challenge ID should return an error."
    },
    {
      "name": "nonexistent_challenge_id",
      "input": {
        "challenge_id": "99999"
      },
      "output": "Error: Challenge not found",
      "notes": "A valid format but nonexistent challenge ID should return a not found error."
    },
    {
      "name": "mobile_layout_check",
      "input": {
        "challenge_id": "12345",
        "device": "mobile"
      },
      "output": "https://api.topcoder-dev.com/challenges/12345",
      "notes": "Ensure mobile layout correctly opens the API URL."
    },
    {
      "name": "challenge_details_dropdown",
      "input": {
        "challenge_id": "12345"
      },
      "output": "https://topcoder-dev.com/challenges/12345",
      "notes": "Challenge details dropdown should return the correct challenge URL."
    },
    {
      "name": "invalid_challenge_id_numeric",
      "input": {
        "challenge_id": "-1"
      },
      "output": "Error: Invalid challenge ID",
      "notes": "Negative numeric challenge ID should return an error."
    }
  ],
  "assumptions": "Challenge IDs are expected to be alphanumeric and non-empty.",
  "notes": "Ensure that all tests cover both valid and invalid scenarios."
}
